+        // 1000.0 should clamp to 127 and -1000.0 should clamp to -128.
+        let x = session
+            .tensor_variable(vec![1000.0, -1000.0, 50.0], vec![3], false)
+            .expect("variable");
+        let q = session
+            .tensor_quantize_per_tensor(x, 1.0, 0, -128, 127)
+            .expect("quantize");
