+        assert!((vals[0] - 127.0).abs() < 1e-9, "high clamp: got {}", vals[0]);
+        assert!((vals[1] + 128.0).abs() < 1e-9, "low clamp: got {}", vals[1]);
+        assert!((vals[2] - 50.0).abs() < 1e-9, "in-range: got {}", vals[2]);
